import React, { createContext, useContext, useEffect, useMemo, useReducer, useState } from "react";
import { io } from "socket.io-client";
import { PLAYERS, ROUND_CONFIG, DURATIONS } from "../utils/constants";
import { load, save } from "../utils/storage";
import { uniqueSequence, repeatingSequence } from "../utils/random";
import { cumulativePrice, calcPlayerPnL } from "../utils/pnl";

const GameContext = createContext(null);

const initialGameState = {
    round: 1,
    currentBox: 0,
    boxes: Array(6).fill(null),
    phase: 'sell',
    timer: 15, // 15 seconds for sell phase
    offers: [], // Active offers
    numbers: [], // Will be populated during reveal phase
    players: {}
};

export function GameProvider({ children }) {
    const [gameState, setGameState] = useState(initialGameState);
    const [socket, setSocket] = useState(null);

    // Handle timer countdown
    useEffect(() => {
        let interval;
        if (gameState.phase === 'sell' && gameState.timer > 0) {
            interval = setInterval(() => {
                setGameState(prev => ({
                    ...prev,
                    timer: prev.timer - 1
                }));
            }, 1000);
        }

        return () => clearInterval(interval);
    }, [gameState.phase, gameState.timer]);

    // Handle phase transitions
    useEffect(() => {
        if (gameState.phase === 'sell' && gameState.timer === 0) {
            setGameState(prev => ({
                ...prev,
                phase: 'reveal',
                timer: 2.5 // 2.5 seconds for number reveal
            }));
        }
    }, [gameState.timer]);

    // Handle number generation during reveal phase
    useEffect(() => {
        let timeout;
        if (gameState.phase === 'reveal') {
            timeout = setTimeout(() => {
                const newNumber = Math.floor(Math.random() * 100) + 1;
                setGameState(prev => ({
                    ...prev,
                    boxes: prev.boxes.map((box, i) => 
                        i === prev.currentBox ? newNumber : box
                    ),
                    currentBox: prev.currentBox + 1,
                    phase: prev.currentBox === 5 ? 'end' : 'sell',
                    timer: 15 // Reset timer for next sell phase
                }));
            }, 2500); // 2.5 seconds delay
        }

        return () => clearTimeout(timeout);
    }, [gameState.phase]);

    // Handle offer placement
    const placeOffer = useCallback((price) => {
        if (gameState.phase !== 'sell' || gameState.timer <= 0) {
            console.error('Cannot place offer now');
            return;
        }

        const offer = {
            id: Date.now(),
            price,
            sellerId: socket?.id,
            expiresAt: Date.now() + (gameState.timer * 1000)
        };

        socket?.emit('place_offer', offer);
    }, [gameState.phase, gameState.timer, socket]);

    // Socket event handlers
    useEffect(() => {
        if (!socket) return;

        socket.on('offer_placed', (offer) => {
            setGameState(prev => ({
                ...prev,
                offers: [...(prev.offers || []), offer]
            }));
        });

        socket.on('offer_expired', (offerId) => {
            setGameState(prev => ({
                ...prev,
                offers: prev.offers.filter(o => o.id !== offerId)
            }));
        });

        return () => {
            socket.off('offer_placed');
            socket.off('offer_expired');
        };
    }, [socket]);

    const value = {
        gameState,
        placeOffer,
        timer: gameState.timer
    };

    return (
        <GameContext.Provider value={value}>
            {children}
        </GameContext.Provider>
    );
}
